sp_angular_provider.script:
/* Use this Directive to show an opening scene with a label, icon and content for Primary Asignee
//
// Copyrights belong to Discover Technologies LLC. © 2023 Discover Technologies LLC
// Special License Rights
//  The Government's rights to use, display, or disclose this software are restricted.
//  Any reproduction of computer software, computer software documentation,
//  or portions thereof marked with this legend must also reproduce the markings. 
// Script Continued Below
//-----------------------------------------------------------------------------------------------------
// 2.8.5 | 2023-11-28 | raj | Updates to make work for TemplateTask
// 2.8.5 | 2023-07-10 | raj | STRY0141856 - Stretch- PLACEHOLDER- Office Control
//
//-----------------------------------------------------------------------------------------------------
*/
function dtechAssignment(getTemplateUrl, spModal, $timeout) {

	var dtechDirective = {
		restrict: 'E',
		// replace: true,
		// @: string 1 way, =: object 2 way, <: object 1 way,
		// &: execute an expression in the context of the parent scope, ?: the binding is optional
		scope: {
			dtechIsDark:"<",
			dtechExcludeWarning:"<",
			dtechIsModal: "<",
			dtechPopoverPlacement: '@?',
			dtechShowLabel: "<?",
			dtechTable: '@',
			dtechTaskSysId: '@',
			dtechToolTipOpen: "=?",
			dtechAssignmentObject: '<',
			dtechField: '<',
			dtechTaskTitle: "<?"
		},
		controller: directiveCtrl,
		link: link,
		controllerAs: 'd',
		templateUrl: getTemplateUrl('x_153465_discovert_dtechAssignment.html')
	};
	return dtechDirective;

	function directiveCtrl($scope, $attrs, $animate, dtechTaskService, dtechTemplateService) {
		var d = this;

		// have local per directive instead of global - TODO: get from a service
		var CONST_TEMP_WAIT_DURATION = 600;
		// STRY0139742 - Increase delaying when hover directives open; TODO: get from a service
		var CONST_POPOVER_DELAY = 1200;
		var CONST_SPINNER_DELAY = 500;

		// STRY0145237 - Directive - update to local var
		var isOverTooltip = false;
		var isClosing = false;

		// STRY0145237 - Directive - Duration code; 
		var parentMouseLeaveTimeouts = []; // added an array to collect each time mouse leave fires; need to cancel time-outs on destroy

		$scope.dtechToolTipOpen = false;

		d.enterTooltip = _enterTooltip;
		d.getImage = _getImage;
		d.init = _init;

		// STRY0139742 - Increase delaying when hover directives open; added
		d.initTooltip = _initTooltip;

		d.leaveTooltip = _leaveTooltip;
		d.openModal= _openModal;
		d.parentMouseLeave = _parentMouseLeave;

		// STRY0139742 - Increase delaying when hover directives open; 
		d.popoverDelay = CONST_POPOVER_DELAY;  // added to set popover-popup-delay in the Macro HTML

		d.popoverTemplate = $scope.dtechAssignmentObject.objectType + '-popover-assignment.html';

		d.showAssignment = _showAssignment;

		// when the user hovers over the tooltip set overtooltip flag
		function _enterTooltip(){
			isOverTooltip = true;
		}

		function _getImage(){
			var imageName = "Member16.svg";
			// only change to white if dark and using original image
			if(imageName=="Member16.svg" && $scope.dtechIsDark==true){
				imageName = "x_153465_discovert.Assignment_White16.svg";
			}
			return imageName;
		}

		// init()
		// initialize the control, called from the Link function
		// gets a reference to the element
		function _init(rawAttrs) {
			// Set a default value when attribute not in hosting HTML
			if (angular.isUndefined(rawAttrs.dtechPopoverPlacement)) {
				$scope.dtechPopoverPlacement = "auto";
			}

			// Set a default value when attribute not in hosting HTML
			if (angular.isUndefined(rawAttrs.dtechShowLabel)) {
				$scope.dtechShowLabel = false;
			}

			// Set default value when attribute not in hosting HTML
			if (angular.isUndefined(rawAttrs.dtechTaskTitle)) {
				if($scope.dtechAssignmentObject){
					$scope.dtechTaskTitle = $scope.dtechAssignmentObject.assignmentTitle;
				}
			}

			$scope.dtechToolTipOpen = 
				angular.isDefined($attrs.dtechToolTipOpen) ?
				$scope.$parent.$eval($attrs.dtechToolTipOpen) : false;			
		}

		// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; added function
		function _initTooltip() {
			// if the user moved off of the parent before the tooltip opened, cancel the open
			if (isClosing == true) {
				_leaveTooltip();
				isClosing = false;
			}
		}

		function _leaveTooltip(){
			isOverTooltip = false;
			$scope.dtechToolTipOpen = false;

			// STRY0139742 - Increase delaying when hover directives open; set true
			isClosing = true;
		}

		// openModal()
		// this function is called from Template html
		// it is called when a user clicks on the Open User Profile link
		function _openModal(event) {
			var title = $scope.dtechTaskTitle;
			if ($scope.dtechAssignmentObject.objectType=='templateTask' || 
				$scope.dtechAssignmentObject.objectType=='task') {
					// MWMTest; update
					x_153465_discovert.twJS.openAssignmentModal(spModal, title, $scope.dtechTable, $scope.dtechTaskSysId);

					// popover closes quickly and user is left watching the spinner before modal pops
					d.leaveTooltip();

					// modal is openened stop the row or cell click form raising
					event.stopPropagation();
			}
		}

		function _parentMouseLeave() {
			// STRY0145237 - Directive - Duration code changes to match design; 
			// we need to track each time the below fires so we cancel on destroy
			parentMouseLeaveTimeouts.push($timeout(function() {
				if(!isOverTooltip){
					d.leaveTooltip();
				}
			}, CONST_TEMP_WAIT_DURATION));
		}

		// STRY0145237 - Directive - Duration code changes to match design;
		function _showAssignment() {
			$scope.dtechToolTipOpen = true;

			// STRY0139742 - Increase delaying when hover directives open; set false
			isClosing = false;

			var assignmentObject = $scope.dtechAssignmentObject;
			if(!assignmentObject){
				assignmentObject = {};
				assignmentObject.taskId = $scope.dtechTaskSysId;
				assignmentObject.loaded = false;
			}
			if(!assignmentObject.loaded  || assignmentObject.taskId != $scope.dtechTaskSysId){
				$scope.dtechAssignmentObject.loaded=false;
				var dtechObject;
				if($scope.dtechAssignmentObject.objectType=='task'){
					dtechTaskService.getAssignmentInformation($scope.dtechTaskSysId).then(
						function(response){
							_responseRecieved(response);
						});
				} else if($scope.dtechAssignmentObject.objectType=='templateTask'){
					dtechTemplateService.getAssignmentInformation($scope.dtechTaskSysId).then(
						function(response){
							_responseRecieved(response);
						});
				}
			}
			$scope.dtechAssignmentObject=assignmentObject;
		}

		function _responseRecieved(response){
			$timeout(function(){
				_setDTechObject(response.assignmentInformation);
				}, CONST_SPINNER_DELAY);
		}

		function _setDTechObject(dtechObject){
			$scope.dtechAssignmentObject = dtechObject;
			$scope.dtechAssignmentObject.loaded = true;
		}

		// STRY0145237 - Directive - Duration code changes to match design; added
		$scope.$on("$destroy", function () {
			// we tracked each time mouse leave fired, now we can cancel each time-out and remove from the array
			angular.forEach(parentMouseLeaveTimeouts, function(item) {
				$timeout.cancel(item);
				parentMouseLeaveTimeouts.splice(parentMouseLeaveTimeouts.indexOf(item), 1);
			});
		});
	}

	// Link function links local methods to parent controller methods
	// see the list of events being monitored
	function link(scope, element, attrs, directiveCtrl){
		// initialize the control
		directiveCtrl.init(attrs);			
		scope.$on('$destroy',_destroy);
		// get the location of the element hovering over

		function _destroy(){
			element.remove();
		}
	}

}
